import { query } from '@/lib/db'
import { SOVEREIGN_CLIENT_GENERATION_TARGET } from '@/lib/outbound-copy'

const HUMAN_MATCHED_REPLY_SQL = `
  COALESCE(metadata->>'matched_to_outbound', 'false') = 'true'
  AND COALESCE(metadata->>'is_auto_response', 'false') <> 'true'
  AND NOT (
    LOWER(
      COALESCE(metadata->>'subject', '') || ' ' ||
      COALESCE(metadata->>'body', '') || ' ' ||
      COALESCE(metadata->>'body_text', '')
    ) LIKE ANY (ARRAY[
      '%auto-generated email%',
      '%autogenerated email%',
      '%automated email%',
      '%automatic reply%',
      '%out of office%',
      '%ticket no%',
      '%ticket number%',
      '%thanks for writing to us%',
      '%we will get back to you within%',
      '%do not reply%'
    ])
  )
`

const HUMAN_MATCHED_REPLY_EVENT_SQL = HUMAN_MATCHED_REPLY_SQL.replaceAll('metadata', 'e.metadata')

export type OutboundTelegramDigest = {
  sentToday: number
  sent24h: number
  failed24h: number
  bounced24h: number
  replies24h: number
  replyRate24h: number
  sent7d: number
  replies7d: number
  replyRate7d: number
  followUpsDue: number
  followUpsPending: number
  followUpsSent24h: number
  followUpsStopped24h: number
  queuedNow: number
  approvedReadyNow: number
  approvedAgencyReadyNow: number
  approvedDirectReadyNow: number
  queuePending: number
  queueProcessing: number
  queueRetry: number
  queueFailed: number
  queueCompleted24h: number
  agencySent24h: number
  directSent24h: number
  agencyReplies24h: number
  directReplies24h: number
  remainingToOperatingFloor: number
  /** Most frequent failure error string in the last 24h, or null if no failures */
  topFailureReason: string | null
  /** Heuristic next-action recommendation based on current system state */
  nextAction: string
  lastEvents: Array<{
    type: 'sent' | 'failed' | 'bounced' | 'reply'
    email: string
    subject: string
    reason?: string
    ts: string
  }>
}

function safeInt(value: unknown): number {
  const n = Number(value)
  return Number.isFinite(n) ? Math.trunc(n) : 0
}

function replyRate(sent: number, replies: number): number {
  if (sent <= 0) return 0
  return Math.round((replies / sent) * 1000) / 10
}

export async function getOutboundTelegramDigest(clientId: number): Promise<OutboundTelegramDigest> {
  try {
    const [eventsRes, followUpsRes, queueRes, approvedRes, mixRes] = await Promise.all([
      // Delivery events: sent / failed / bounce + reply signals from events table
      query<{
        event_type: string
        bucket: string
        cnt: string
      }>(
        `SELECT
           event_type,
           CASE
             WHEN created_at >= NOW() - INTERVAL '24 hours' AND DATE(created_at AT TIME ZONE 'UTC') = CURRENT_DATE AT TIME ZONE 'UTC' THEN 'today_and_24h'
             WHEN created_at >= NOW() - INTERVAL '24 hours' THEN 'h24'
             WHEN created_at >= NOW() - INTERVAL '7 days' THEN 'd7'
             ELSE 'older'
           END AS bucket,
           COUNT(*) AS cnt
         FROM events
         WHERE client_id = $1
           AND event_type IN ('sent','failed','bounce','reply','bounced')
           AND (
             event_type <> 'reply'
             OR (${HUMAN_MATCHED_REPLY_SQL})
           )
           AND created_at >= NOW() - INTERVAL '7 days'
         GROUP BY 1, 2`,
        [clientId]
      ),

      // Follow-up tracking from queue_jobs
      query<{
        status: string
        is_followup: string
        updated_today: string
        cnt: string
      }>(
        `SELECT
           status,
           CASE WHEN COALESCE(metadata->>'step_number','0')::int > 1 THEN 'true' ELSE 'false' END AS is_followup,
           CASE WHEN updated_at >= NOW() - INTERVAL '24 hours' THEN 'true' ELSE 'false' END AS updated_today,
           COUNT(*) AS cnt
         FROM queue_jobs
         WHERE client_id = $1
           AND created_at >= NOW() - INTERVAL '30 days'
         GROUP BY 1, 2, 3`,
        [clientId]
      ).catch(() => ({ rows: [] as {status:string;is_followup:string;updated_today:string;cnt:string}[], rowCount: 0 })),

      // Current queue health. Keep compatibility with legacy BullMQ-like statuses.
      query<{
        pending: string
        processing: string
        retry: string
        failed: string
        completed_24h: string
      }>(
        `SELECT
           COUNT(*) FILTER (WHERE status IN ('pending','waiting','delayed'))::text AS pending,
           COUNT(*) FILTER (WHERE status IN ('processing','active'))::text AS processing,
           COUNT(*) FILTER (WHERE status = 'retry')::text AS retry,
           COUNT(*) FILTER (WHERE status = 'failed')::text AS failed,
           COUNT(*) FILTER (
             WHERE status = 'completed'
               AND updated_at >= NOW() - INTERVAL '24 hours'
           )::text AS completed_24h
         FROM queue_jobs
         WHERE client_id = $1`,
        [clientId]
      ).catch(() => ({
        rows: [{ pending: '0', processing: '0', retry: '0', failed: '0', completed_24h: '0' }],
        rowCount: 1,
      })),

      // Approved inventory that can be queued on the next cycle.
      query<{
        total: string
        agency: string
        direct: string
      }>(
        `WITH approved AS (
           SELECT
             c.*,
             LOWER(
               COALESCE(c.custom_fields->>'offer_type','') || ' ' ||
               COALESCE(c.custom_fields->>'sovereign_offer_type','') || ' ' ||
               COALESCE(c.company,'') || ' ' ||
               COALESCE(c.title,'') || ' ' ||
               COALESCE(c.source,'') || ' ' ||
               COALESCE(c.custom_fields->>'reason_to_contact','')
             ) AS signal
           FROM contacts c
           WHERE c.client_id = $1
             AND c.status = 'active'
             AND c.bounced_at IS NULL
             AND c.unsubscribed_at IS NULL
             AND COALESCE(c.custom_fields->>'send_status', 'not_approved') = 'approved'
             AND NOT EXISTS (
               SELECT 1
               FROM suppression_list s
               WHERE s.client_id = c.client_id
                 AND LOWER(s.email) = LOWER(c.email)
             )
         )
         SELECT
           COUNT(*)::text AS total,
           COUNT(*) FILTER (
             WHERE signal ~ '(agency|revops|lead.?gen|outbound|marketing|white.?label|consult)'
           )::text AS agency,
           COUNT(*) FILTER (
             WHERE NOT (signal ~ '(agency|revops|lead.?gen|outbound|marketing|white.?label|consult)')
           )::text AS direct
         FROM approved`,
        [clientId]
      ).catch(() => ({ rows: [{ total: '0', agency: '0', direct: '0' }], rowCount: 1 })),

      // Offer mix and reply split for the executive hourly report.
      query<{
        agency_sent_24h: string
        direct_sent_24h: string
        agency_replies_24h: string
        direct_replies_24h: string
      }>(
        `SELECT
           COUNT(*) FILTER (
             WHERE event_type = 'sent'
               AND created_at >= NOW() - INTERVAL '24 hours'
               AND COALESCE(metadata->>'offer_type','') = 'agency'
           )::text AS agency_sent_24h,
           COUNT(*) FILTER (
             WHERE event_type = 'sent'
               AND created_at >= NOW() - INTERVAL '24 hours'
               AND COALESCE(metadata->>'offer_type','direct') <> 'agency'
           )::text AS direct_sent_24h,
           COUNT(*) FILTER (
             WHERE event_type = 'reply'
               AND created_at >= NOW() - INTERVAL '24 hours'
               AND (${HUMAN_MATCHED_REPLY_SQL})
               AND COALESCE(metadata->>'offer_type','') = 'agency'
           )::text AS agency_replies_24h,
           COUNT(*) FILTER (
             WHERE event_type = 'reply'
               AND created_at >= NOW() - INTERVAL '24 hours'
               AND (${HUMAN_MATCHED_REPLY_SQL})
               AND COALESCE(metadata->>'offer_type','direct') <> 'agency'
           )::text AS direct_replies_24h
         FROM events
         WHERE client_id = $1
           AND created_at >= NOW() - INTERVAL '24 hours'`,
        [clientId]
      ).catch(() => ({
        rows: [{ agency_sent_24h: '0', direct_sent_24h: '0', agency_replies_24h: '0', direct_replies_24h: '0' }],
        rowCount: 1,
      })),
    ])

    // Aggregate event counts
    let sentToday = 0
    let sent24h = 0
    let failed24h = 0
    let bounced24h = 0
    let replies24h = 0
    let sent7d = 0
    let replies7d = 0

    for (const row of eventsRes.rows) {
      const cnt = safeInt(row.cnt)
      const type = row.event_type
      const bucket = row.bucket

      const isSent = type === 'sent'
      const isFailed = type === 'failed'
      const isBounce = type === 'bounce' || type === 'bounced'
      const isReply = type === 'reply'

      if (bucket === 'today_and_24h') {
        if (isSent) { sentToday += cnt; sent24h += cnt }
        if (isFailed) failed24h += cnt
        if (isBounce) bounced24h += cnt
        if (isReply) replies24h += cnt
      } else if (bucket === 'h24') {
        if (isSent) sent24h += cnt
        if (isFailed) failed24h += cnt
        if (isBounce) bounced24h += cnt
        if (isReply) replies24h += cnt
      }

      // 7d totals include today_and_24h and h24 and d7
      if (bucket !== 'older') {
        if (isSent) sent7d += cnt
        if (isReply) replies7d += cnt
      }
    }

    // Follow-up aggregation
    let followUpsDue = 0
    let followUpsPending = 0
    let followUpsSent24h = 0
    let followUpsStopped24h = 0

    for (const row of followUpsRes.rows) {
      if (row.is_followup !== 'true') continue
      const cnt = safeInt(row.cnt)
      const status = row.status
      const recentlyUpdated = row.updated_today === 'true'

      if (status === 'pending' || status === 'waiting' || status === 'delayed') {
        followUpsPending += cnt
        // due = pending follow-ups whose scheduled time has passed (approximate via status)
        if (status === 'waiting') followUpsDue += cnt
      }
      if (status === 'completed' && recentlyUpdated) followUpsSent24h += cnt
      if ((status === 'stopped' || status === 'cancelled') && recentlyUpdated) followUpsStopped24h += cnt
    }

    const queuePending = safeInt(queueRes.rows[0]?.pending)
    const queueProcessing = safeInt(queueRes.rows[0]?.processing)
    const queueRetry = safeInt(queueRes.rows[0]?.retry)
    const queueFailed = safeInt(queueRes.rows[0]?.failed)
    const queueCompleted24h = safeInt(queueRes.rows[0]?.completed_24h)
    const queuedNow = queuePending
    const approvedReadyNow = safeInt(approvedRes.rows[0]?.total)
    const approvedAgencyReadyNow = safeInt(approvedRes.rows[0]?.agency)
    const approvedDirectReadyNow = safeInt(approvedRes.rows[0]?.direct)
    const agencySent24h = safeInt(mixRes.rows[0]?.agency_sent_24h)
    const directSent24h = safeInt(mixRes.rows[0]?.direct_sent_24h)
    const agencyReplies24h = safeInt(mixRes.rows[0]?.agency_replies_24h)
    const directReplies24h = safeInt(mixRes.rows[0]?.direct_replies_24h)
    const remainingToOperatingFloor = Math.max(
      0,
      SOVEREIGN_CLIENT_GENERATION_TARGET.operatingSendFloor - sentToday
    )

    // Top failure reason in last 24h
    const topFailureRes = await query<{ error: string; cnt: string }>(
      `SELECT
         COALESCE(NULLIF(TRIM(metadata->>'error'),''), NULLIF(TRIM(metadata->>'reason'),''), 'unknown') AS error,
         COUNT(*) AS cnt
       FROM events
       WHERE client_id = $1
         AND event_type IN ('failed','bounce','bounced')
         AND created_at >= NOW() - INTERVAL '24 hours'
         AND COALESCE(NULLIF(TRIM(metadata->>'error'),''), NULLIF(TRIM(metadata->>'reason'),'')) IS NOT NULL
       GROUP BY 1
       ORDER BY cnt DESC
       LIMIT 1`,
      [clientId]
    ).catch(() => ({ rows: [] as { error: string; cnt: string }[], rowCount: 0 }))

    const topFailureReason = topFailureRes.rows[0]?.error ?? null

    // Heuristic next-action
    function deriveNextAction(): string {
      if (failed24h > sent24h * 0.1 && sent24h > 0) {
        return `High failure rate (${failed24h}/${sent24h}). Check SMTP credentials and domain health first.`
      }
      if (bounced24h > 2) {
        return `${bounced24h} bounces detected. Tighten approval quality and suppress bounced patterns before the next client-generation cycle.`
      }
      if (replies24h > 0 && followUpsStopped24h < replies24h) {
        return `${replies24h} replies — verify follow-ups are stopped for replied contacts.`
      }
      if (queuedNow === 0 && sentToday === 0) {
        return 'Nothing queued or sent today. Build buyer-fit approved inventory before the next client-generation cycle.'
      }
      if (queuedNow > 0 && sentToday === 0) {
        return `${queuedNow} jobs queued but 0 sent. Check sender worker is running on Render.`
      }
      if (followUpsDue > 0) {
        return `${followUpsDue} follow-ups are due. Ensure sequence worker is processing them.`
      }
      if (
        sentToday >= SOVEREIGN_CLIENT_GENERATION_TARGET.operatingSendFloor &&
        replies24h < SOVEREIGN_CLIENT_GENERATION_TARGET.dailyQualifiedConversationsMin
      ) {
        return `Client-generation target not hit yet: volume is in range (${sentToday} today), so tighten buyer fit, approval quality, and pain-led copy before increasing sends.`
      }
      if (sentToday > 0 && replies24h === 0) {
        return `Sending healthy (${sentToday} today), but below the ${SOVEREIGN_CLIENT_GENERATION_TARGET.operatingSendFloor}-${SOVEREIGN_CLIENT_GENERATION_TARGET.operatingSendCeiling} operating range. Keep building high-intent approved inventory.`
      }
      return 'System nominal. Keep optimizing for qualified client conversations, not raw send count.'
    }

    const nextAction = deriveNextAction()

    // Last 8 events for the digest feed
    const lastEventsRes = await query<{
      event_type: string
      created_at: string
      to_email: string | null
      subject: string | null
      error: string | null
    }>(
      `SELECT
         e.event_type,
         e.created_at::text,
         CASE
           WHEN e.event_type = 'reply' THEN COALESCE(NULLIF(e.metadata->>'from_email',''), co.email)
           ELSE COALESCE(NULLIF(e.metadata->>'to_email',''), NULLIF(e.metadata->>'to',''), co.email)
         END AS to_email,
         COALESCE(NULLIF(e.metadata->>'subject',''), NULLIF(e.metadata->>'email_subject','')) AS subject,
         CASE
           WHEN e.event_type = 'reply' THEN NULLIF(e.metadata->>'body','')
           ELSE COALESCE(NULLIF(e.metadata->>'error',''), NULLIF(e.metadata->>'reason',''))
         END AS error
       FROM events e
       LEFT JOIN contacts co ON co.id = e.contact_id AND co.client_id = e.client_id
       WHERE e.client_id = $1
         AND (
           e.event_type IN ('sent','failed','bounce','bounced')
           OR (
             e.event_type = 'reply'
             AND (${HUMAN_MATCHED_REPLY_EVENT_SQL})
           )
         )
       ORDER BY e.created_at DESC
       LIMIT 8`,
      [clientId]
    )

    const lastEvents = lastEventsRes.rows.map((r) => ({
      type: (r.event_type === 'bounce' || r.event_type === 'bounced' ? 'bounced' : r.event_type) as 'sent' | 'failed' | 'bounced' | 'reply',
      email: r.to_email ?? '',
      subject: (r.subject ?? '').slice(0, 80),
      reason: r.error ?? undefined,
      ts: r.created_at,
    }))

    return {
      sentToday,
      sent24h,
      failed24h,
      bounced24h,
      replies24h,
      replyRate24h: replyRate(sent24h, replies24h),
      sent7d,
      replies7d,
      replyRate7d: replyRate(sent7d, replies7d),
      followUpsDue,
      followUpsPending,
      followUpsSent24h,
      followUpsStopped24h,
      queuedNow,
      approvedReadyNow,
      approvedAgencyReadyNow,
      approvedDirectReadyNow,
      queuePending,
      queueProcessing,
      queueRetry,
      queueFailed,
      queueCompleted24h,
      agencySent24h,
      directSent24h,
      agencyReplies24h,
      directReplies24h,
      remainingToOperatingFloor,
      topFailureReason,
      nextAction,
      lastEvents,
    }
  } catch (error) {
    console.error('[outbound-telegram-digest] failed', error)
    // Return zeroed digest so Telegram still fires
    return {
      sentToday: 0,
      sent24h: 0,
      failed24h: 0,
      bounced24h: 0,
      replies24h: 0,
      replyRate24h: 0,
      sent7d: 0,
      replies7d: 0,
      replyRate7d: 0,
      followUpsDue: 0,
      followUpsPending: 0,
      followUpsSent24h: 0,
      followUpsStopped24h: 0,
      queuedNow: 0,
      approvedReadyNow: 0,
      approvedAgencyReadyNow: 0,
      approvedDirectReadyNow: 0,
      queuePending: 0,
      queueProcessing: 0,
      queueRetry: 0,
      queueFailed: 0,
      queueCompleted24h: 0,
      agencySent24h: 0,
      directSent24h: 0,
      agencyReplies24h: 0,
      directReplies24h: 0,
      remainingToOperatingFloor: SOVEREIGN_CLIENT_GENERATION_TARGET.operatingSendFloor,
      topFailureReason: null,
      nextAction: 'Digest query failed — check DB connectivity.',
      lastEvents: [],
    }
  }
}
